#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>
#define MAX 500000
#define INF 1000000000

// Structure to represent a graph
typedef struct {
    int n;
    int m;
    int **adj;
} Graph;

// Function to create a graph
Graph *createGraph(int n, int m) {
    Graph *graph = (Graph *)malloc(sizeof(Graph));
    graph->n = n;
    graph->m = m;
    graph->adj = (int **)malloc(n * sizeof(int *));
    for (int i = 0; i < n; i++) {
        graph->adj[i] = (int *)malloc(m * sizeof(int));
    }
    return graph;
}

// Function to perform BFS
int bfs(Graph *graph, int start, int end) {
    int *dist = (int *)malloc(graph->n * sizeof(int));
    bool *visited = (bool *)malloc(graph->n * sizeof(bool));
    for (int i = 0; i < graph->n; i++) {
        dist[i] = INF;
        visited[i] = false;
    }
    dist[start] = 0;
    visited[start] = true;
    int *queue = (int *)malloc(graph->n * sizeof(int));
    int front = 0, rear = 0;
    queue[rear++] = start;
    while (front < rear) {
        int u = queue[front++];
        for (int i = 0; i < graph->m; i++) {
            if (graph->adj[u][i] == 1 && !visited[i]) {
                dist[i] = dist[u] + 1;
                visited[i] = true;
                queue[rear++] = i;
            }
        }
    }
    int minActions = dist[end];
    free(dist);
    free(visited);
    free(queue);
    return minActions;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m;
        scanf("%d %d", &n, &m);
        Graph *graph = createGraph(n, m);
        for (int i = 0; i < m; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            graph->adj[u - 1][v - 1] = 1;
        }
        int minActions = bfs(graph, 0, n - 1);
        if (minActions == INF) {
            printf("-1\n");
        } else {
            printf("%d\n", minActions);
        }
        free(graph->adj);
        free(graph);
    }
    return 0;
}

