// Structure to represent a graph
struct Graph {
    int n;
    int m;
    vector<vector<int>> adj;
};

// Function to create a graph
Graph createGraph(int n, int m) {
    Graph graph;
    graph.n = n;
    graph.m = m;
    graph.adj.resize(n, vector<int>(m, 0));
    return graph;
}

// Function to perform BFS
int bfs(Graph &graph, int start, int end) {
    vector<int> dist(graph.n, 1000000000);
    vector<bool> visited(graph.n, false);
    dist[start] = 0;
    visited[start] = true;
    queue<int> q;
    q.push(start);
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (int i = 0; i < graph.m; i++) {
            if (graph.adj[u][i] == 1 && !visited[i]) {
                dist[i] = dist[u] + 1;
                visited[i] = true;
                q.push(i);
            }
        }
    }
    int minActions = dist[end];
    return minActions;
}

