import java.util.Scanner;
import java.util.Queue;
import java.util.LinkedList;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            int n = sc.nextInt();
            int m = sc.nextInt();
            int[][] adj = new int[n][m];
            for (int i = 0; i < m; i++) {
                int u = sc.nextInt() - 1;
                int v = sc.nextInt() - 1;
                adj[u][v] = 1;
            }
            int minActions = bfs(adj, 0, n - 1);
            if (minActions == 1000000000) {
                System.out.println(-1);
            } else {
                System.out.println(minActions);
            }
        }
    }

    public static int bfs(int[][] adj, int start, int end) {
        int n = adj.length;
        int m = adj[0].length;
        int[] dist = new int[n];
        boolean[] visited = new boolean[n];
        for (int i = 0; i < n; i++) {
            dist[i] = 1000000000;
            visited[i] = false;
        }
        dist[start] = 0;
        visited[start] = true;
        Queue<Integer> q = new LinkedList<>();
        q.add(start);
        while (!q.isEmpty()) {
            int u = q.poll();
            for (int i = 0; i < m; i++) {
                if (adj[u][i] == 1 && !visited[i]) {
                    dist[i] = dist[u] + 1;
                    visited[i] = true;
                    q.add(i);
                }
            }
        }
        int minActions = dist[end];
        return minActions;
    }
}

